import React from 'react';
import { PokemonWithStats } from '../types/pokemonChampions';
import { XIcon } from '@heroicons/react/outline';

interface PokemonChampionDetailProps {
  pokemon: PokemonWithStats | null;
  onClose: () => void;
}

const PokemonChampionDetail: React.FC<PokemonChampionDetailProps> = ({ pokemon, onClose }) => {
  if (!pokemon) return null;

  const { champion, stats } = pokemon;

  const typeColors: Record<string, string> = {
    Normal: 'bg-gray-400',
    Fire: 'bg-red-500',
    Water: 'bg-blue-500',
    Electric: 'bg-yellow-400',
    Grass: 'bg-green-500',
    Ice: 'bg-cyan-400',
    Fighting: 'bg-red-700',
    Poison: 'bg-purple-500',
    Ground: 'bg-yellow-600',
    Flying: 'bg-indigo-400',
    Psychic: 'bg-pink-500',
    Bug: 'bg-lime-500',
    Rock: 'bg-yellow-700',
    Ghost: 'bg-purple-700',
    Dragon: 'bg-indigo-600',
    Dark: 'bg-gray-800',
    Steel: 'bg-gray-600',
    Fairy: 'bg-pink-400',
  };

  const abilityColors: string[] = [
    'bg-orange-400',
    'bg-teal-400',
    'bg-amber-400',
    'bg-rose-400',
    'bg-sky-400',
    'bg-emerald-400',
    'bg-violet-400',
    'bg-fuchsia-400',
  ];

  const getAbilityColor = (abilityName: string) => {
    const hash = abilityName.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
    return abilityColors[hash % abilityColors.length];
  };

  const getPokemonImageUrl = (name: string, dexNumber: number) => {
    return `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${dexNumber}.png`;
  };

  const combatStats = [
    { name: 'HP', value: stats.hp },
    { name: 'Attack', value: stats.atk },
    { name: 'Defense', value: stats.def },
    { name: 'Special Attack', value: stats.spa },
    { name: 'Special Defense', value: stats.spd },
    { name: 'Speed', value: stats.spe }
  ];

  const maxStat = Math.max(...combatStats.map(stat => stat.value));

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-lg max-w-4xl w-full max-h-[90vh] overflow-y-auto">
        <div className="sticky top-0 bg-white border-b p-4 flex justify-between items-center">
          <h2 className="text-2xl font-bold">
            {champion.name} - {champion.form}
          </h2>
          <button
            onClick={onClose}
            className="p-2 hover:bg-gray-100 rounded-full transition-colors"
          >
            <XIcon className="w-6 h-6" />
          </button>
        </div>

        <div className="p-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
              <div className="flex justify-center">
                <img
                  src={getPokemonImageUrl(champion.name, champion.dexNumber)}
                  alt={champion.name}
                  className="w-48 h-48 object-contain"
                  onError={(e) => {
                    (e.target as HTMLImageElement).src = 'https://via.placeholder.com/192x192?text=?';
                  }}
                />
              </div>

              <div className="space-y-2">
                <h3 className="text-lg font-semibold">Types</h3>
                <div className="flex flex-wrap gap-2">
                  {champion.types.map((type, index) => (
                    <span
                      key={index}
                      className={`px-3 py-1 text-white rounded-full ${typeColors[type] || 'bg-gray-400'}`}
                    >
                      {type}
                    </span>
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <h3 className="text-lg font-semibold">Basic Info</h3>
                <div className="grid grid-cols-2 gap-2 text-sm">
                  <div className="bg-gray-50 p-2 rounded">
                    <span className="font-medium">Dex #:</span> {champion.dexNumber}
                  </div>
                  <div className="bg-gray-50 p-2 rounded">
                    <span className="font-medium">Form:</span> {champion.form}
                  </div>
                  <div className="bg-gray-50 p-2 rounded">
                    <span className="font-medium">Total Stats:</span> {stats.total}
                  </div>
                  <div className="bg-gray-50 p-2 rounded">
                    <span className="font-medium">Verified:</span> {champion.championsVerified ? 'Yes' : 'No'}
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <div>
                <h3 className="text-lg font-semibold mb-2">Base Stats</h3>
                <div className="space-y-2">
                  {combatStats.map((stat, index) => (
                    <div key={index} className="space-y-1">
                      <div className="flex justify-between text-sm">
                        <span className="font-medium">{stat.name}</span>
                        <span className="font-bold">{stat.value}</span>
                      </div>
                      <div className="w-full bg-gray-200 rounded-full h-2">
                        <div
                          className="bg-blue-500 h-2 rounded-full transition-all duration-300"
                          style={{ width: `${(stat.value / maxStat) * 100}%` }}
                        />
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h3 className="text-lg font-semibold mb-2">Abilities</h3>
                <div className="space-y-1">
                  {Object.entries(champion.abilities).map(([slot, ability], index) => (
                    <div
                      key={index}
                      className={`flex items-center space-x-2 text-sm p-2 rounded ${
                        slot.toLowerCase() === 'h' ? 'bg-gray-100' : 'bg-white border'
                      }`}
                    >
                      <span
                        className={`px-2 py-1 text-xs text-white rounded ${getAbilityColor(ability)}`}
                      >
                        {ability.replace(/-/g, ' ')}
                      </span>
                      <span className="text-gray-600">
                        {slot.toLowerCase() === 'h' ? '(Hidden)' : `(Slot ${slot})`}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PokemonChampionDetail;
